import org.junit.jupiter.api.Test;

/**
 * Test to demonstrate late data side output handling for merging windows.
 *
 * This test exercises the scenario where:
 * 1. An element arrives late (after watermark)
 * 2. Could potentially merge with an existing non-expired window
 * 3. Should be emitted to side output
 */
public class TestSessionWindowLateData {

    private final OutputTag<Tuple2<String, Integer>> lateOutputTag =
            new OutputTag<Tuple2<String, Integer>>("late"){};

    @Test
    void testLateElementInMergingSessionWindow() throws Exception {
        final int gapSize = 5;  // 5 second gap
        final long allowedLateness = 0;  // No allowed lateness

        ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
                new ReducingStateDescriptor<>(
                        "window-contents",
                        (a, b) -> new Tuple2<>(a.f0, a.f1 + b.f1),
                        TypeInformation.of(new org.apache.flink.api.common.typeutils.GenericTypeInfo<>(
                                Tuple2.class,
                                String.class,
                                Integer.class
                        )));

        WindowOperator<String, Tuple2<String, Integer>, Tuple2<String, Integer>,
                Tuple3<String, Long, Long>, TimeWindow> operator =
                new WindowOperator<>(
                        EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                        new TimeWindow.Serializer(),
                        new org.apache.flink.api.java.functions.KeySelector<Tuple2<String, Integer>, String>() {
                            @Override
                            public String getKey(Tuple2<String, Integer> value) {
                                return value.f0;
                            }
                        },
                        BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                new org.apache.flink.api.common.ExecutionConfig().getSerializerConfig()),
                        stateDesc,
                        new InternalWindowFunction<Tuple2<String, Integer>, Tuple3<String, Long, Long>,
                                String, TimeWindow>() {
                            @Override
                            public void process(String key, TimeWindow window,
                                    InternalWindowFunction.InternalWindowContext context,
                                    Tuple2<String, Integer> input,
                                    org.apache.flink.util.Collector<Tuple3<String, Long, Long>> out) {
                                out.collect(new Tuple3<>(key, window.getStart(), window.getEnd()));
                            }

                            @Override
                            public void clear(TimeWindow window,
                                    InternalWindowFunction.InternalWindowContext context) {
                            }
                        },
                        EventTimeTrigger.create(),
                        allowedLateness,
                        lateOutputTag);

        OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
                harness = new OneInputStreamOperatorTestHarness<>(operator);

        harness.open();

        // Scenario:
        // 1. Element arrives at timestamp 1000, creates window [1000, 1005]
        // 2. Watermark advances to 1010 (window is now "late" - cleanup time is 1005)
        // 3. Another element arrives at timestamp 1003 (which is LATE - 1003 + 0 <= 1010)
        // 4. This element COULD merge with the first window, creating [1000, 1008]
        // 5. But the merged window is ALSO late (1008 + 0 <= 1010)
        // 6. The element should be sent to side output, but might be silently dropped

        System.out.println("Step 1: Process element at ts=1000");
        harness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 1000L));

        System.out.println("Step 2: Advance watermark to 1010 (window now late)");
        harness.processWatermark(new Watermark(1010L));

        System.out.println("Step 3: Process late element at ts=1003 (should be sent to side output)");
        harness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 1003L));

        // Check outputs
        var mainOutput = harness.getOutput();
        var sideOutput = harness.getSideOutput(lateOutputTag);

        System.out.println("Main output: " + mainOutput);
        System.out.println("Side output: " + sideOutput);

        // The late element should be in the side output
        assert !sideOutput.isEmpty() : "Late element should be in side output";

        harness.close();
    }
}

