    final long allowedLateness = 0; // No allowed lateness

    ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
            new ReducingStateDescriptor<>(
                    "window-contents",
                    new SumReducer(),
                    STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

    WindowOperatorFactory<
                    String,
                    Tuple2<String, Integer>,
                    Tuple2<String, Integer>,
                    Tuple3<String, Long, Long>,
                    TimeWindow>
            operator =
                    new WindowOperatorFactory<>(
                            EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                            new TimeWindow.Serializer(),
                            new TupleKeySelector(),
                            BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                    new SerializerConfigImpl()),
                            stateDesc,
                            new InternalSingleValueWindowFunction<>(
                                    new ReducedSessionWindowFunction()),
                            EventTimeTrigger.create(),
                            allowedLateness,
                            lateOutputTag);

    OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
            testHarness = createTestHarness(operator);

    testHarness.open();

    ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
    ConcurrentLinkedQueue<Object> sideExpected = new ConcurrentLinkedQueue<>();

    // Element 1: Create first window [1000, 1003]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 1000));
    testHarness.processWatermark(new Watermark(1001));
    expected.add(new Watermark(1001));

    // Element 2: Create second window [2000, 2003]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 2000));
    testHarness.processWatermark(new Watermark(2001));
    expected.add(new Watermark(2001));

    // Element 3: Merge element at 1500 merges both windows -> [1000, 2003]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 1500));
    testHarness.processWatermark(new Watermark(3499));
    expected.add(new Watermark(3499));

    // Watermark to 5500: merged window [1000, 2003] cleanup time = 2003 + 0 = 2003
    // Is 2003 <= 5500? YES, window is late
    testHarness.processWatermark(new Watermark(5500));
    expected.add(new StreamRecord<>(new Tuple3<>("key-3", 1000L, 2003L), 2002));
    expected.add(new Watermark(5500));

    // Element 4: Late element at 1800 (late because 1800 + 0 <= 5500)
    // This SHOULD extend the window even though the window is "late" for cleanup
    // because the element can merge with the existing [1000, 2003] window
    // BEFORE fix: Window would be skipped, element lost
    // AFTER fix: Window merges, creating [1000, 2003] (no change), element processed
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key", 1), 1800));

    // The merged window should fire immediately (because merged window is after watermark)
    expected.add(new StreamRecord<>(new Tuple3<>("key-4", 1000L, 2003L), 2002));

    testHarness.processWatermark(new Watermark(10000));
    expected.add(new Watermark(10000));

    ConcurrentLinkedQueue<Object> actual = testHarness.getOutput();
    ConcurrentLinkedQueue<StreamRecord<Tuple2<String, Integer>>> sideActual =
            testHarness.getSideOutput(lateOutputTag);

    TestHarnessUtil.assertOutputEqualsSorted(
            "Output was not correct.", expected, actual, new Tuple3ResultSortComparator());

    // With the fix, no elements should be in side output
    // (the late element should have been merged and processed)
    if (sideActual != null) {
        assertThat(sideActual).isEmpty();
    }

    testHarness.close();
}

